// 1. Pin agent.json to IPFS (any pinning provider)
const { uri } = await fetch('/api/ipfs/upload', {
  method: 'POST',
  body: JSON.stringify({ module: { schema: 'erc-8004/v1', name: 'My Agent', /* ... */ }})
}).then(r => r.json());

// 2. Call Adapter8004.registerAndBind
await wallet.writeContract({
  address: ADAPTER_8004, abi: ADAPTER_ABI, functionName: 'registerAndBind',
  args: [NORMIES_CONTRACT, tokenId, uri]
});

// 3. Verify
const agentId = await client.readContract({
  address: ADAPTER_8004, abi: ADAPTER_ABI, functionName: 'getAgentIdByToken',
  args: [NORMIES_CONTRACT, tokenId]
});
console.log('Bound agent', agentId);
